import React, { useState, useRef, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useChat } from '../contexts/ChatContext';
// MOCK MODE: Using mock wallet
import { useWallet } from '../contexts/MockWalletContext';
// import { useWallet } from '../contexts/WalletContext'; // Uncomment for real MetaMask
import { 
  Send, 
  ArrowLeft, 
  Users, 
  Hash,
  Star,
  ExternalLink,
  Loader
} from 'lucide-react';
import { format } from 'date-fns';

const ChatRoom = () => {
  const { roomId } = useParams();
  const { chatRooms, messages, sendMessage, mintMessageAsNFT } = useChat();
  const { walletAddress } = useWallet();
  const [newMessage, setNewMessage] = useState('');
  const [mintingMessage, setMintingMessage] = useState(null);
  const messagesEndRef = useRef(null);

  const room = chatRooms.find(r => r.id === roomId);
  const roomMessages = messages[roomId] || [];

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [roomMessages]);

  const handleSendMessage = (e) => {
    e.preventDefault();
    if (newMessage.trim()) {
      sendMessage(roomId, newMessage.trim());
      setNewMessage('');
    }
  };

  const handleMintMessage = async (messageId) => {
    setMintingMessage(messageId);
    try {
      const result = await mintMessageAsNFT(messageId, roomId);
      if (result.success) {
        alert(`Message minted as NFT! Token ID: ${result.tokenId}`);
      }
    } catch (error) {
      alert('Failed to mint message as NFT');
    } finally {
      setMintingMessage(null);
    }
  };

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const isOwnMessage = (sender) => sender === walletAddress;

  if (!room) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Room not found</h2>
          <Link to="/dashboard" className="btn-primary">
            Back to Dashboard
          </Link>
        </div>
      </div>
    );
  }

  if (!room.hasAccess) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Access Denied</h2>
          <p className="text-gray-600 mb-4">You need the required NFT to access this room</p>
          <Link to="/dashboard" className="btn-primary">
            Back to Dashboard
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      {/* Room Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <Link
              to="/dashboard"
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors duration-200"
            >
              <ArrowLeft className="w-5 h-5 text-gray-600" />
            </Link>
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 bg-primary-100 rounded-lg flex items-center justify-center">
                <Hash className="w-5 h-5 text-primary-600" />
              </div>
              <div>
                <h1 className="text-lg font-semibold text-gray-900">{room.name}</h1>
                <div className="flex items-center space-x-2 text-sm text-gray-500">
                  <Users className="w-4 h-4" />
                  <span>{room.memberCount} members</span>
                  {room.isActive && (
                    <>
                      <span>•</span>
                      <div className="flex items-center space-x-1">
                        <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
                        <span>Active</span>
                      </div>
                    </>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-4">
        {roomMessages.map((message) => (
          <div
            key={message.id}
            className={`flex ${isOwnMessage(message.sender) ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                isOwnMessage(message.sender)
                  ? 'bg-primary-600 text-white'
                  : 'bg-white border border-gray-200'
              }`}
            >
              <div className="flex items-center justify-between mb-1">
                <span className={`text-xs font-medium ${
                  isOwnMessage(message.sender) ? 'text-primary-100' : 'text-gray-600'
                }`}>
                  {isOwnMessage(message.sender) ? 'You' : formatAddress(message.sender)}
                </span>
                <span className={`text-xs ${
                  isOwnMessage(message.sender) ? 'text-primary-200' : 'text-gray-500'
                }`}>
                  {format(message.timestamp, 'HH:mm')}
                </span>
              </div>
              <p className="text-sm">{message.content}</p>
              
              {/* IPFS and Mint Info */}
              <div className="mt-2 pt-2 border-t border-opacity-20 border-gray-300">
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <ExternalLink className="w-3 h-3 opacity-60" />
                    <span className="text-xs opacity-75">
                      IPFS: {message.ipfsHash.slice(0, 8)}...
                    </span>
                  </div>
                  
                  {message.canMint && isOwnMessage(message.sender) && (
                    <button
                      onClick={() => handleMintMessage(message.id)}
                      disabled={mintingMessage === message.id}
                      className="flex items-center space-x-1 text-xs bg-white bg-opacity-20 hover:bg-opacity-30 px-2 py-1 rounded transition-colors duration-200"
                    >
                      {mintingMessage === message.id ? (
                        <Loader className="w-3 h-3 animate-spin" />
                      ) : (
                        <Star className="w-3 h-3" />
                      )}
                      <span>Mint NFT</span>
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Message Input */}
      <div className="bg-white border-t border-gray-200 p-6">
        <form onSubmit={handleSendMessage} className="flex space-x-4">
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            placeholder="Type your message..."
            className="flex-1 input-field"
          />
          <button
            type="submit"
            disabled={!newMessage.trim()}
            className="btn-primary flex items-center space-x-2"
          >
            <Send className="w-4 h-4" />
            <span>Send</span>
          </button>
        </form>
        <p className="text-xs text-gray-500 mt-2">
          Messages are stored on IPFS and can be minted as NFTs
        </p>
      </div>
    </div>
  );
};

export default ChatRoom;
